      },
      {
        "name": "PostgreSQL Primary + Hot Standby",
        "responsibility": "Single source of truth for courier availability state and assignment records. Primary handles all writes; synchronous replication to standby ensures no data loss on failover.",
        "boundaries": "Owns courier_assignments and courier_availability tables. Patroni or pg_auto_failover manages automatic promotion."
      },
      {
        "name": "Courier Availability Cache",
        "responsibility": "In-process (not Redis) LRU cache of courier availability zones, refreshed every 1-2 seconds from the DB. Used ONLY for pre-filtering candidates before the authoritative DB lock. Reduces query load and helps meet 200ms target.",
        "boundaries": "Read-only, eventually consistent. Never used for assignment decisions — only for narrowing candidates."
      },
      {
        "name": "Order Events Consumer",
        "responsibility": "Listens to order-placed events from the order service (Kafka/SQS/simple webhook). Triggers the assignment flow. Handles retries and dead-letter for failed assignments.",
        "boundaries": "Thin adapter layer — transforms order events into assignment requests."
      },
      {
        "name": "Heartbeat & Availability Tracker",
        "responsibility": "Receives periodic courier GPS/status pings. Updates courier_availability in the database. Marks couriers as unavailable after heartbeat timeout.",
        "boundaries": "Write path for courier state. Decoupled from assignment path to avoid contention."
      }
    ],
    "interfaces": [
      {
        "from": "Order Events Consumer",
        "to": "Assignment Service",
        "contract": "assignCourier(orderId, pickupLocation, deliveryLocation) -> {courierId, estimatedPickupTime} | AssignmentFailure",
        "coupling_type": "synchronous — internal function call within the same service boundary"
      },
      {
        "from": "Assignment Service",
        "to": "PostgreSQL Primary",
        "contract": "BEGIN; SELECT id FROM couriers WHERE available=true AND zone=? ORDER BY distance LIMIT 1 FOR UPDATE SKIP LOCKED; INSERT INTO assignments(...); UPDATE couriers SET available=false; COMMIT;",
        "coupling_type": "tight — transactional consistency required"
      },
      {
        "from": "Heartbeat Tracker",
        "to": "PostgreSQL Primary",
        "contract": "UPDATE couriers SET last_seen=now(), location=point(?,?) WHERE id=?",
        "coupling_type": "loose — eventual consistency acceptable for location updates"
      },
      {
        "from": "Assignment Service",
        "to": "Courier Availability Cache",
        "contract": "getCandidateCouriers(zone, pickupLocation) -> List<CourierId>",
        "coupling_type": "loose — cache miss falls through to DB query"
      }
    ],
    "data_flow": "1. Order placed → event consumed → Assignment Service invoked. 2. Service queries in-process cache for candidate couriers near pickup zone. 3. Single atomic transaction: SELECT FOR UPDATE SKIP LOCKED on best candidate → INSERT assignment → UPDATE courier availability → COMMIT. 4. If no courier available, return failure (order service retries or escalates). 5. Courier heartbeats flow separately into availability tracker, updating the DB and refreshing caches.",
    "patterns_used": [
      {
        "pattern": "SELECT FOR UPDATE SKIP LOCKED",
        "rationale": "PostgreSQL's row-level locking with SKIP LOCKED gives us both strong consistency (no double-assignment) and high throughput (concurrent assignment requests skip already-locked couriers instead of blocking). This is the critical pattern that makes 200ms feasible under contention."
      },
      {
        "pattern": "Single-Primary with Synchronous Replication + Auto-Failover",
        "rationale": "CP architecture. Synchronous replication to hot standby means zero data loss. Patroni/pg_auto_failover provides automated promotion in 5-15 seconds. This is the simplest path to strong consistency + practical availability for a 2-person team."
      },
      {
        "pattern": "In-Process Cache (not distributed cache)",
        "rationale": "Redis would add another infrastructure component for a 2-person team to manage. An in-process LRU cache refreshed from DB every 1-2s reduces query load without adding operational burden. Cache is never authoritative."
      },
      {
        "pattern": "Idempotent Assignment with Order-Based Deduplication",
        "rationale": "UNIQUE constraint on (order_id) in assignments table prevents duplicate assignments on retry. Combined with SKIP LOCKED, retries are safe and fast."
      }
    ]
  },

  "domain_model": {
    "bounded_contexts": [
      {
        "name": "Courier Assignment",
        "classification": "core",
        "aggregates": [
          "CourierAvailability (aggregate root: courier_id, available, current_zone, last_location, last_seen_at)",
          "Assignment (aggregate root: assignment_id; entities: order_id, courier_id, status, assigned_at, picked_up_at, delivered_at)"
        ]
      },
      {
        "name": "Order Management",
        "classification": "supporting",
        "aggregates": [
          "Order — owned by upstream service, not modeled here. We consume order-placed events."
        ]
      },
      {
        "name": "Courier Profile",
        "classification": "supporting",
        "aggregates": [
          "CourierProfile — owned by upstream service. We consume courier onboarding/deactivation events."
        ]
      }
    ],
    "context_map": [
      {
        "upstream": "Order Management",
        "downstream": "Courier Assignment",
        "relationship": "Customer-Supplier — Order Management publishes order-placed events; Assignment consumes them. Assignment service does not influence the order model."
