    "level": 58,
    "high_confidence_areas": [
      "CP over AP is the correct trade-off — double-assignment has higher business cost than brief unavailability",
      "SELECT FOR UPDATE SKIP LOCKED is the right primitive for atomic courier locking",
      "PostgreSQL single-primary is appropriate for a 2-engineer team",
      "In-process cache over Redis reduces operational burden without sacrificing correctness"
    ],
    "low_confidence_areas": [
